from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["first-pc-autopilot-ready-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>God Mode Today Ready</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0;--ok:#22c55e;--warn:#f59e0b;--bad:#ef4444}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#173766,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel,.card{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:8px}button{font:inherit;border-radius:16px;border:0;background:linear-gradient(135deg,#0284c7,#38bdf8);color:#02101b;padding:12px;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}.check{border-left:4px solid var(--ok);padding:9px 10px;background:#081226;border-radius:14px}.bad{border-left-color:var(--bad)}.score{font-size:48px;font-weight:1000}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:520px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}.score{font-size:36px}}</style></head><body><div class="page"><section class="panel"><h1>God Mode Today Ready</h1><p class="muted">Caminho rápido para instalar/abrir no PC e iniciar o primeiro loop autónomo seguro.</p><div class="buttons"><button onclick="location.href='/app/home'" class="dark">Home</button><button onclick="location.href='/app/artifacts-center'" class="dark">Artifacts</button><button onclick="location.href='/app/god-mode-vault'" class="dark">Vault</button><button onclick="location.href='/app/mobile-permission-relay'" class="dark">Mobile Relay</button><button onclick="location.href='/app/ia-operator-bridge'" class="dark">IA Bridge</button><button onclick="readiness()">Readiness</button><button onclick="start()">Start Autopilot</button></div></section><section class="panel"><h2>Ready score</h2><div id="score" class="score">...</div><p id="sentence" class="muted"></p></section><section class="panel"><h2>Checks</h2><div id="checks" class="grid"></div></section><section class="panel"><h2>Passos rápidos</h2><div id="steps" class="grid"></div></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function esc(s){return String(s??'').replaceAll('<','&lt;')}function show(x){qs('#out').textContent=JSON.stringify(x,null,2);render(x)}function render(x){const r=x?.readiness||x; const score=r?.ready_score??x?.status?.ready_score??'...'; qs('#score').textContent=score+'%'; qs('#sentence').textContent=x?.launch_contract?.one_sentence||x?.one_sentence||''; const checks=r?.checks||[]; qs('#checks').innerHTML=checks.map(c=>`<div class="check ${c.ok?'':'bad'}"><b>${esc(c.name)}</b><br>${c.ok?'OK':'FAIL'}<br><span class="muted">${esc(c.route)}</span></div>`).join(''); const steps=(x?.steps?.pc_steps||x?.pc_steps||[]); qs('#steps').innerHTML=steps.map(s=>`<div class="check"><b>${esc(s.step)}. ${esc(s.title)}</b><br><span class="muted">${esc(s.note)}</span><br>${esc(s.route)}</div>`).join('')}async function readiness(){show(await api('/api/first-pc-autopilot-ready/package'))}async function start(){show(await api('/api/first-pc-autopilot-ready/start-today-autopilot',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({tenant_id:'owner-andre'})}))}readiness()</script></body></html>
"""


@router.get('/app/first-pc-autopilot-ready', response_class=HTMLResponse)
async def first_pc_autopilot_ready_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/today-ready', response_class=HTMLResponse)
async def today_ready_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
